import { h, Component } from 'preact';
import style from './style';

// Import the Web Workers
import WebWorker from '../../workers/workerSetup';
import dataWorker from '../../workers/dataWorker';
import analyzingWorker from '../../workers/analyzingWorker';

export default class Home extends Component {

	constructor(props) {
		super(props);

		this.state = {
			county: '',
			data: [],
			averageAge: 0,
			averageDemocratAge: 0,
			averageNpaAge: 0,
			averageOtherAge: 0,
			averageRepublicanAge: 0,
			blacks: 0,
			democrats: 0,
			females: 0,
			hispanics: 0,
			males: 0,
			npas: 0,
			otherRace: 0,
			republicans: 0,
			thirdPartyVoters: 0,
			totalVoters: 0,
			unkownGenders: 0,
			whites: 0
		};
	}

	loadCountyData = (county) => {
		let url = '';

		switch(county) {
			case 'Brevard':
				url = 'https://raw.githubusercontent.com/mgrigajtis/mgrigajtis.github.io/master/d5/data/data.json';
				break;
			case 'Citrus':
				url = 'https://raw.githubusercontent.com/mgrigajtis/mgrigajtis.github.io/master/citrus/data/data.json';
				break;
			default:
				this.setState({ data: [] });
				break;
		}

		if (county !== '') {
			let dataworker = new WebWorker(dataWorker);
			document.getElementById('countyLoading').classList.remove(style.hidden);

			dataworker.onmessage = (e) => {
				this.setState({ data: e.data.data });
				document.getElementById('countyLoading').classList.add(style.hidden);

				dataworker.postMessage(['close']);
			};

			dataworker.postMessage([url]);
		}
	};

	countyChanged = (e) => {
		this.setState({ county: e.target.value } );

		this.loadCountyData(e.target.value);
	};

	analyzeData = () => {
		let worker = new WebWorker(analyzingWorker);

		worker.onmessage = (e) => {
			let returnData = e.data;

			this.setState({
				averageAge: returnData.averageAge,
				averageDemocratAge: returnData.averageDemocratAge,
				averageNpaAge: returnData.averageNpaAge,
				averageOtherAge: returnData.averageOtherAge,
				averageRepublicanAge: returnData.averageRepublicanAge,
				blacks: returnData.blacks,
				democrats: returnData.democrats,
				females: returnData.females,
				hispanics: returnData.hispanics,
				males: returnData.males,
				npas: returnData.npas,
				otherRace: returnData.otherRace,
				republicans: returnData.republicans,
				thirdPartyVoters: returnData.thirdPartyVoters,
				totalVoters: returnData.totalVoters,
				unkownGenders: returnData.unkownGenders,
				whites: returnData.whites
			});

			worker.postMessage(['close']);
		};

		worker.postMessage([this.state.data]);
	};

	render() {
		return (
			<div class={style.home}>
				<div class={style.debug}>
					Selected County: {this.state.county}<br />
					Total Voters: {this.state.data.length}<br />
					Average Age: {this.state.averageAge}<br />
					Average Democrat Age: {this.state.averageDemocratAge}<br />
					Average NPA Age: {this.state.averageNpaAge}<br />
					Average Other Age: {this.state.averageOtherAge}<br />
					Average Republican Age: {this.state.averageRepublicanAge}<br />
					Blacks: {this.state.blacks}<br />
					Democrats: {this.state.democrats}<br />
					Females: {this.state.females}<br />
					Hispanics: {this.state.hispanics}<br />
					Males: {this.state.males}<br />
					NPAs: {this.state.npas}<br />
					Other Race: {this.state.otherRace}<br />
					Republicans: {this.state.republicans}<br />
					Third Party Voters: {this.state.thirdPartyVoters}<br />
					Total Voters: {this.state.totalVoters}<br />
					Unkown Genders: {this.state.unkownGenders}<br />
					Whites: {this.state.whites}
				</div>

				<div>
					<label for="county">Select County</label><br />
					<select id="county" onChange={this.countyChanged}>
						<option value="">Select County</option>
						<option value="Brevard">Brevard</option>
						<option value="Citrus">Citrus</option>
					</select>
					<span class={style.hidden} id="countyLoading">Loading...</span>
				</div>

				<div>
					<button onClick={this.analyzeData}>Analyze</button>
				</div>

				<div>

				</div>
			</div>
		);
	}
}
